import { useState } from "react";
import { useNavigate } from "react-router-dom";
import ClientLayout from "../../components/layout/ClientLayout";
import { createOrder, geocodeAddress, getRouteInfo, getWeather } from "../../api/clientApi";
import { VehicleSVG } from "../";
import "../../styles/client/CreateOrder.css";

const VEHICLE_TYPES = [
  { id: "car",   label: "Легковой",  icon: "car",   maxKg: 200,   pricePerKm: 25  },
  { id: "van",   label: "Фургон",    icon: "van",   maxKg: 1500,  pricePerKm: 45  },
  { id: "truck", label: "Грузовик",  icon: "truck", maxKg: 5000,  pricePerKm: 80  },
];

const WEATHER_MULTIPLIERS = {
  0: 1.0,  // clear
  1: 1.0, 2: 1.0, 3: 1.0,  // mainly clear / overcast
  45: 1.15, 48: 1.2,  // fog
  51: 1.1, 53: 1.1, 55: 1.15,  // drizzle
  61: 1.15, 63: 1.2, 65: 1.25,  // rain
  71: 1.3, 73: 1.35, 75: 1.4,  // snow
  80: 1.15, 81: 1.2, 82: 1.3,  // showers
  95: 1.4, 96: 1.45, 99: 1.5,  // thunderstorm
};

const WEATHER_NAMES = {
  0: "Ясно", 1: "Преимущественно ясно", 2: "Переменная облачность", 3: "Пасмурно",
  45: "Туман", 48: "Морозный туман",
  51: "Слабая морось", 53: "Морось", 55: "Сильная морось",
  61: "Слабый дождь", 63: "Умеренный дождь", 65: "Ливень",
  71: "Слабый снег", 73: "Умеренный снег", 75: "Сильный снег",
  80: "Небольшой ливень", 81: "Ливень", 82: "Сильный ливень",
  95: "Гроза", 96: "Гроза с градом", 99: "Гроза с крупным градом",
};

function getWeatherName(code) {
  return WEATHER_NAMES[code] || "Неизвестно";
}

export default function CreateOrder() {
  const navigate = useNavigate();

  const [form, setForm] = useState({
    pickupAddress:   "",
    deliveryAddress: "",
    requestedTime:   "",
    weightKg:        "",
    lengthCm:        "",
    widthCm:         "",
    heightCm:        "",
    vehicleType:     "car",
    comment:         "",
  });

  const [calc, setCalc]       = useState(null);
  const [calcLoading, setCL]  = useState(false);
  const [calcError, setCE]    = useState("");
  const [submitting, setSub]  = useState(false);
  const [success, setSuccess] = useState(false);

  const set = (k, v) => setForm(p => ({ ...p, [k]: v }));

  /* ── CALCULATE ── */
  const handleCalculate = async () => {
    if (!form.pickupAddress || !form.deliveryAddress) {
      setCE("Введите оба адреса"); return;
    }
    setCE(""); setCL(true); setCalc(null);
    try {
      const [fromCoords, toCoords] = await Promise.all([
        geocodeAddress(form.pickupAddress),
        geocodeAddress(form.deliveryAddress),
      ]);

      if (!fromCoords || !toCoords) {
        setCE("Не удалось определить координаты адресов. Уточните адрес."); setCL(false); return;
      }

      const [route, weather] = await Promise.all([
        getRouteInfo(fromCoords, toCoords),
        getWeather(fromCoords.lat, fromCoords.lng),
      ]);

      const vt         = VEHICLE_TYPES.find(v => v.id === form.vehicleType);
      const baseMin    = route.durationMin;
      const weatherMul = WEATHER_MULTIPLIERS[weather?.weathercode] || 1.0;

      // Traffic congestion: rough estimate based on time of day
      const hour = new Date().getHours();
      const trafficMul = (hour >= 7 && hour <= 9) || (hour >= 17 && hour <= 20) ? 1.35 : 1.0;

      const totalMin   = Math.round(baseMin * weatherMul * trafficMul);
      const price      = Math.round(route.distanceKm * vt.pricePerKm * weatherMul);

      setCalc({
        distanceKm:  route.distanceKm.toFixed(1),
        baseMin:     Math.round(baseMin),
        totalMin,
        price,
        weatherCode: weather?.weathercode,
        temperature: weather?.temperature,
        windspeed:   weather?.windspeed,
        weatherMul,
        trafficMul,
        vehicleType: vt,
      });
    } catch (e) {
      setCE("Ошибка при расчёте. Проверьте адреса.");
    } finally { setCL(false); }
  };

  /* ── SUBMIT ── */
  const handleSubmit = async () => {
    if (!form.pickupAddress || !form.deliveryAddress) return;
    setSub(true);
    try {
      await createOrder({
        pickupAddress:   form.pickupAddress,
        deliveryAddress: form.deliveryAddress,
        requestedTime:   form.requestedTime || null,
        latitude:        calc?.lat || null,
        longitude:       calc?.lng || null,
      });
      setSuccess(true);
      setTimeout(() => navigate("/client/orders"), 2000);
    } catch {
      setCE("Ошибка при создании заказа");
    } finally { setSub(false); }
  };

  if (success) return (
    <ClientLayout>
      <div className="co-root">
        <div className="co-success">
          <div className="co-success-icon">✅</div>
          <h2>Заказ успешно создан!</h2>
          <p>Перенаправляем в историю заказов...</p>
        </div>
      </div>
    </ClientLayout>
  );

  return (
    <ClientLayout>
      <div className="co-root">
        <div className="co-hero">
          <h1 className="co-title">Новый заказ</h1>
          <p className="co-sub">Заполните форму — система рассчитает стоимость с учётом пробок и погоды</p>
        </div>

        <div className="co-grid">

          {/* ── FORM ── */}
          <div className="co-form-col">

            {/* Addresses */}
            <div className="co-card">
              <div className="co-card-title">📍 Адреса</div>
              <div className="co-field">
                <label>Адрес отправки</label>
                <input
                  className="co-input"
                  placeholder="ул. Ленина, 10, Москва"
                  value={form.pickupAddress}
                  onChange={e => set("pickupAddress", e.target.value)}
                />
              </div>
              <div className="co-field">
                <label>Адрес доставки</label>
                <input
                  className="co-input"
                  placeholder="ул. Тверская, 5, Москва"
                  value={form.deliveryAddress}
                  onChange={e => set("deliveryAddress", e.target.value)}
                />
              </div>
              <div className="co-field">
                <label>Желаемое время доставки</label>
                <input
                  className="co-input"
                  type="datetime-local"
                  value={form.requestedTime}
                  onChange={e => set("requestedTime", e.target.value)}
                />
              </div>
            </div>

            {/* Cargo */}
            <div className="co-card">
              <div className="co-card-title">📦 Параметры груза</div>
              <div className="co-row">
                <div className="co-field">
                  <label>Вес (кг)</label>
                  <input className="co-input" type="number" placeholder="50" value={form.weightKg} onChange={e => set("weightKg", e.target.value)} />
                </div>
                <div className="co-field">
                  <label>Длина (см)</label>
                  <input className="co-input" type="number" placeholder="100" value={form.lengthCm} onChange={e => set("lengthCm", e.target.value)} />
                </div>
              </div>
              <div className="co-row">
                <div className="co-field">
                  <label>Ширина (см)</label>
                  <input className="co-input" type="number" placeholder="50" value={form.widthCm} onChange={e => set("widthCm", e.target.value)} />
                </div>
                <div className="co-field">
                  <label>Высота (см)</label>
                  <input className="co-input" type="number" placeholder="50" value={form.heightCm} onChange={e => set("heightCm", e.target.value)} />
                </div>
              </div>
              <div className="co-field">
                <label>Комментарий</label>
                <textarea
                  className="co-input co-textarea"
                  placeholder="Хрупкий груз, требует аккуратного обращения..."
                  value={form.comment}
                  onChange={e => set("comment", e.target.value)}
                />
              </div>
            </div>

            {/* Vehicle type */}
            <div className="co-card">
              <div className="co-card-title">🚗 Тип транспорта</div>
              <div className="co-vehicles">
                {VEHICLE_TYPES.map(vt => (
                  <button
                    key={vt.id}
                    className={`co-vehicle-btn ${form.vehicleType === vt.id ? "co-vehicle-btn--active" : ""}`}
                    onClick={() => set("vehicleType", vt.id)}
                  >
                    <VehicleSVG type={vt.icon} size={70} />
                    <div className="co-vehicle-label">{vt.label}</div>
                    <div className="co-vehicle-info">до {vt.maxKg.toLocaleString()} кг</div>
                  </button>
                ))}
              </div>
            </div>

            <div className="co-actions">
              <button className="co-calc-btn" onClick={handleCalculate} disabled={calcLoading}>
                {calcLoading ? "⏳ Рассчитываем..." : "🧮 Рассчитать стоимость"}
              </button>
              <button
                className="co-submit-btn"
                onClick={handleSubmit}
                disabled={submitting || !form.pickupAddress || !form.deliveryAddress}
              >
                {submitting ? "Создаём заказ..." : "Создать заказ →"}
              </button>
            </div>

            {calcError && <div className="co-error">{calcError}</div>}
          </div>

          {/* ── RESULT ── */}
          <div className="co-result-col">
            {!calc && !calcLoading && (
              <div className="co-result-placeholder">
                <span>🧮</span>
                <p>Заполните адреса и нажмите<br />«Рассчитать стоимость»</p>
              </div>
            )}
            {calcLoading && (
              <div className="co-result-placeholder">
                <div className="co-spinner" />
                <p>Запрашиваем данные о маршруте, погоде и пробках...</p>
              </div>
            )}
            {calc && (
              <div className="co-result-card">
                <div className="co-result-title">Расчёт доставки</div>

                <div className="co-result-main">
                  <div className="co-result-price">
                    {calc.price.toLocaleString()} ₽
                  </div>
                  <div className="co-result-time">
                    ⏱ {calc.totalMin >= 60
                      ? `${Math.floor(calc.totalMin/60)} ч ${calc.totalMin % 60} мин`
                      : `${calc.totalMin} мин`}
                  </div>
                </div>

                <div className="co-result-divider" />

                <div className="co-result-rows">
                  <div className="co-result-row">
                    <span>📏 Расстояние</span>
                    <strong>{calc.distanceKm} км</strong>
                  </div>
                  <div className="co-result-row">
                    <span>🚗 Транспорт</span>
                    <strong>{calc.vehicleType.label}</strong>
                  </div>
                  <div className="co-result-row">
                    <span>⏰ Базовое время</span>
                    <strong>{calc.baseMin} мин</strong>
                  </div>
                  <div className="co-result-row">
                    <span>🌡 Температура</span>
                    <strong>{calc.temperature}°C</strong>
                  </div>
                  <div className="co-result-row">
                    <span>🌦 Погода</span>
                    <strong>{getWeatherName(calc.weatherCode)}</strong>
                  </div>
                  {calc.weatherMul > 1.0 && (
                    <div className="co-result-row co-result-row--warn">
                      <span>🌦 Коэффициент погоды</span>
                      <strong>×{calc.weatherMul.toFixed(2)}</strong>
                    </div>
                  )}
                  {calc.trafficMul > 1.0 && (
                    <div className="co-result-row co-result-row--warn">
                      <span>🚦 Час пик (пробки)</span>
                      <strong>×{calc.trafficMul.toFixed(2)}</strong>
                    </div>
                  )}
                </div>

                {(calc.weatherMul > 1.0 || calc.trafficMul > 1.0) && (
                  <div className="co-result-notice">
                    ⚠ Время увеличено из-за {calc.trafficMul > 1.0 ? "час пика" : ""}{calc.weatherMul > 1.0 && calc.trafficMul > 1.0 ? " и " : ""}{calc.weatherMul > 1.0 ? "неблагоприятной погоды" : ""}
                  </div>
                )}
              </div>
            )}
          </div>

        </div>
      </div>
    </ClientLayout>
  );
}
